import{_ as o,o as t,c as a,ak as d}from"./chunks/framework.BwzOvEE0.js";const u=JSON.parse('{"title":"Changelog","description":"mcp-exec release history — what changed in each version.","frontmatter":{"description":"mcp-exec release history — what changed in each version."},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md","lastUpdated":1779829281000}'),s={name:"changelog.md"};function n(i,e,r,c,l,g){return t(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to mcp-exec are documented here.</p><p>The format follows <a href="https://keepachangelog.com/en/1.0.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>.</p><hr><h2 id="v1-0-0-—-2026-05-26" tabindex="-1">v1.0.0 — 2026-05-26 <a class="header-anchor" href="#v1-0-0-—-2026-05-26" aria-label="Permalink to &quot;v1.0.0 — 2026-05-26&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Token benchmark CI suite</strong> (<code>npm run bench</code>): 7 scenarios covering Salesforce CRM, fan-out queries, stateful sessions, output trimming, error recovery, auth forwarding, and full-stack workflows — all under 5% exec / 10% full-stack token thresholds</li><li><strong>Python MCP imports via HTTP bridge</strong>: <code>from mcp.github import list_pull_requests</code> — auto-generated <code>mcp/</code> package injected into <code>PYTHONPATH</code>, dispatches through local HTTP bridge to real MCP clients</li><li><strong><code>mcp-exec prime [--local]</code></strong> CLI command: idempotently appends skill-activation rule to <code>CLAUDE.md</code>, raising tool invocation reliability from ~40% to 90–95%</li><li><strong><code>mcp-exec env</code> CLI</strong>: full env allowlist management with <code>list</code>, <code>list --all</code>, <code>add</code>, <code>remove</code>, <code>show</code>, and <code>reset</code> subcommands, plus <code>--local</code> flag for project-scope vs user-scope config</li><li><strong>Environment variable allowlist</strong>: sandbox filters env vars by default; <code>sandbox.env.allow</code> in <code>~/.claude/settings.json</code> or <code>.claude/settings.json</code> controls what is forwarded. Default: <code>PATH</code>, <code>HOME</code>, <code>TMPDIR</code>, <code>TMP</code>, <code>TEMP</code>, <code>USER</code>, <code>USERNAME</code>, <code>LANG</code>, <code>LC_ALL</code>, <code>LC_CTYPE</code>, <code>NODE_PATH</code>, <code>SHELL</code></li><li><strong>Codex CLI support</strong>: <code>AGENTS.md</code> agent instructions + <code>.codex-plugin/plugin.json</code> manifest for native Codex plugin registration</li><li><strong>Gemini CLI support</strong>: <code>GEMINI.md</code> with <code>@./skills/...</code> file references for automatic skill loading</li><li><strong>OpenCode.ai support</strong>: <code>.opencode/plugins/mcp-exec.js</code> bootstrap injection, skills auto-discovered, <code>SKILL.md</code> injected on first message</li><li><strong>Full VitePress documentation site</strong>: Guide, User Manual, Developer, and Reference sections covering installation, configuration, runtimes, CLI, security, and case studies</li><li><strong>Skills rewritten to best-practices standard</strong>: <code>using-mcp-exec</code> (when/why to use the sandbox) and <code>mcp-exec-dev-workflow</code> (API exploration and data-processing workflows for active development)</li><li><strong><code>agents/openai.yaml</code> metadata</strong> per skill for Codex UI skill picker integration</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>install-skill</code> command renamed to <code>prime-skill</code> / <code>mcp-exec prime</code> — clearer intent, avoids collision with Claude Code&#39;s own install terminology</li><li>Python runtime now supports MCP tool imports via HTTP bridge (previously limited to data-processing with third-party packages only)</li></ul><hr><h2 id="v0-3-0" tabindex="-1">v0.3.0 <a class="header-anchor" href="#v0-3-0" aria-label="Permalink to &quot;v0.3.0&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Python runtime</strong> via <code>uv run --isolated</code>: stateless subprocess execution, PEP 723 inline dependency declarations, automatic package installation per invocation</li><li><strong><code>py-sdk-reference.md</code></strong> skill: reference guide for Python execution patterns, PEP 723 syntax, and data handoff between Node and Python runtimes</li><li><strong>Explicit <code>session_id</code> parameter</strong>: pass a named session ID to <code>exec()</code> to isolate state across parallel workflows</li></ul><hr><h2 id="v0-2-0" tabindex="-1">v0.2.0 <a class="header-anchor" href="#v0-2-0" aria-label="Permalink to &quot;v0.2.0&quot;">​</a></h2><h3 id="added-2" tabindex="-1">Added <a class="header-anchor" href="#added-2" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Generic MCP shim generator</strong>: replaces hardcoded Gmail/GDrive shims; shims are generated at runtime from the live tool catalog for any connected MCP server</li><li><strong><code>tools(query)</code> with lazy-loaded catalog</strong>: full tool schemas never load into context; <code>tools()</code> returns trimmed summaries; substring AND semantic search supported</li><li><strong>Unavailable server tracking</strong>: servers that fail to connect are tracked with a reason string and surfaced in <code>tools()</code> with <code>status: &quot;unavailable&quot;</code></li><li><strong><code>ts-sdk-reference.md</code></strong> skill: reference guide for TypeScript/Node execution patterns, session management, and MCP tool call patterns</li></ul><hr><h2 id="v0-1-0" tabindex="-1">v0.1.0 <a class="header-anchor" href="#v0-1-0" aria-label="Permalink to &quot;v0.1.0&quot;">​</a></h2><h3 id="added-3" tabindex="-1">Added <a class="header-anchor" href="#added-3" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li><strong>Node.js runtime</strong> with persistent <code>vm.Context</code> sessions: state persists across <code>exec()</code> calls within the same session via <code>globalThis</code></li><li><strong>Bash runtime</strong>: stateless subprocess execution; each call is isolated</li><li><strong><code>exec(code, runtime)</code> tool</strong>: only the return value or stdout enters the LLM context</li><li><strong><code>mcp-exec</code> MCP server</strong> (stdio transport): registers <code>tools</code> and <code>exec</code> tools with Claude Code</li><li><strong><code>.claude-plugin/plugin.json</code></strong> manifest: Claude Code plugin descriptor</li><li><strong><code>install-skill</code> command</strong>: appends skill-loader rule to <code>CLAUDE.md</code></li><li><strong>Implicit sessions</strong> (conversation-scoped) + explicit <code>session_id</code> for parallel isolation</li><li><strong>Sandbox config</strong>: reads <code>sandbox</code> block from <code>~/.claude/settings.json</code> and <code>.claude/settings.json</code></li></ul>',21)])])}const p=o(s,[["render",n]]);export{u as __pageData,p as default};
